  1→import React, { useState, useEffect } from 'react';
  2→import { authenticatedFetch, hasRole } from '../utils/auth';
  3→
  4→interface Release {
  5→    id: number;
  6→    version: string;
  7→    name: string;
  8→    description: string;
  9→    status: 'PREPARATION' | 'ALIGNMENT' | 'ACTIVE' | 'ARCHIVED';
 10→    requirementCount: number;
 11→    releaseDate: string | null;
 12→    createdBy: string;
 13→    createdAt: string;
 14→    updatedAt: string;
 15→}
 16→
 17→interface ReleaseStats {
 18→    currentRelease: Release | null;
 19→    draftCount: number;
 20→    totalReleases: number;
 21→    activeAssessments: number;
 22→}
 23→
 24→const ReleaseManagement = () => {
 25→    const [releases, setReleases] = useState<Release[]>([]);
 26→    const [stats, setStats] = useState<ReleaseStats | null>(null);
 27→    const [loading, setLoading] = useState(true);
 28→    const [error, setError] = useState<string | null>(null);
 29→    const [showCreateModal, setShowCreateModal] = useState(false);
 30→    const [selectedRelease, setSelectedRelease] = useState<Release | null>(null);
 31→    const [showEditModal, setShowEditModal] = useState(false);
 32→
 33→    // RBAC: Only ADMIN or REQADMIN can create/delete releases
 34→    const canCreate = typeof window !== 'undefined' && (hasRole('ADMIN') || hasRole('REQADMIN'));
 35→
 36→    // Form state
 37→    const [formData, setFormData] = useState({
 38→        version: '',
 39→        name: '',
 40→        description: ''
 41→    });
 42→
 43→    useEffect(() => {
 44→        if (typeof window !== 'undefined') {
 45→            loadData();
 46→        }
 47→    }, []);
 48→
 49→    const loadData = async () => {
 50→        try {
 51→            setLoading(true);
 52→            const releasesResponse = await authenticatedFetch('/api/releases');
 53→
 54→            if (!releasesResponse.ok) {
 55→                throw new Error('Failed to load data');
 56→            }
 57→
 58→            const releasesData = await releasesResponse.json();
 59→            setReleases(releasesData);
 60→
 61→            // Calculate stats from releases data
 62→            const activeReleases = releasesData.filter((r: Release) => r.status === 'ACTIVE');
 63→            const preparationReleases = releasesData.filter((r: Release) => r.status === 'PREPARATION');
 64→
 65→            setStats({
 66→                currentRelease: activeReleases[0] || null,
 67→                draftCount: preparationReleases.length,
 68→                totalReleases: releasesData.length,
 69→                activeAssessments: 0
 70→            });
 71→        } catch (err) {
 72→            setError('Failed to load release data');
 73→        } finally {
 74→            setLoading(false);
 75→        }
 76→    };
 77→
 78→    const validateVersion = (version: string): string | null => {
 79→        if (!version.trim()) {
 80→            return 'Version is required';
 81→        }
 82→        // Check semantic versioning format (major.minor.patch)
 83→        if (!/^\d+\.\d+\.\d+$/.test(version.trim())) {
 84→            return 'Version must follow semantic versioning format (e.g., 1.0.0)';
 85→        }
 86→        return null;
 87→    };
 88→
 89→    const handleCreateRelease = async () => {
 90→        try {
 91→            // Validate version format before sending request
 92→            const versionError = validateVersion(formData.version);
 93→            if (versionError) {
 94→                setError(versionError);
 95→                return;
 96→            }
 97→
 98→            if (!formData.name.trim()) {
 99→                setError('Release name is required');
100→                return;
101→            }
102→
103→            const response = await authenticatedFetch('/api/releases', {
104→                method: 'POST',
105→                headers: {
106→                    'Content-Type': 'application/json',
107→                },
108→                body: JSON.stringify(formData)
109→            });
110→
111→            if (!response.ok) {
112→                if (response.status === 401) {
113→                    setError('Authentication required. Please log in again.');
114→                    // Optionally redirect to login
115→                    setTimeout(() => {
116→                        window.location.href = '/login';
117→                    }, 2000);
118→                    return;
119→                }
120→                const errorData = await response.json();
121→                throw new Error(errorData.error || 'Failed to create release');
122→            }
123→
124→            setShowCreateModal(false);
125→            setFormData({ version: '', name: '', description: '' });
126→            setError(null); // Clear any previous errors
127→            loadData();
128→        } catch (err) {
129→            setError(err instanceof Error ? err.message : 'Failed to create release');
130→        }
131→    };
132→
133→    const handleEditRelease = async () => {
134→        if (!selectedRelease) return;
135→
136→        try {
137→            const response = await authenticatedFetch(`/api/releases/${selectedRelease.id}`, {
138→                method: 'PUT',
139→                headers: {
140→                    'Content-Type': 'application/json',
141→                },
142→                body: JSON.stringify(formData)
143→            });
144→
145→            if (!response.ok) {
146→                const errorData = await response.json();
147→                throw new Error(errorData.error || 'Failed to update release');
148→            }
149→
150→            setShowEditModal(false);
151→            setSelectedRelease(null);
152→            setFormData({ version: '', name: '', description: '' });
153→            loadData();
154→        } catch (err) {
155→            setError(err instanceof Error ? err.message : 'Failed to update release');
156→        }
157→    };
158→
159→    const handlePublishRelease = async (releaseId: number) => {
160→        try {
161→            const response = await authenticatedFetch(`/api/releases/${releaseId}/publish`, {
162→                method: 'POST'
163→            });
164→
165→            if (!response.ok) {
166→                const errorData = await response.json();
167→                throw new Error(errorData.error || 'Failed to publish release');
168→            }
169→
170→            loadData();
171→        } catch (err) {
172→            setError(err instanceof Error ? err.message : 'Failed to publish release');
173→        }
174→    };
175→
176→    const handleArchiveRelease = async (releaseId: number) => {
177→        try {
178→            const response = await authenticatedFetch(`/api/releases/${releaseId}/archive`, {
179→                method: 'POST'
180→            });
181→
182→            if (!response.ok) {
183→                const errorData = await response.json();
184→                throw new Error(errorData.error || 'Failed to archive release');
185→            }
186→
187→            loadData();
188→        } catch (err) {
189→            setError(err instanceof Error ? err.message : 'Failed to archive release');
190→        }
191→    };
192→
193→    const handleDeleteRelease = async (releaseId: number) => {
194→        if (!confirm('Are you sure you want to delete this release? This action cannot be undone.')) {
195→            return;
196→        }
197→
198→        try {
199→            const response = await authenticatedFetch(`/api/releases/${releaseId}`, {
200→                method: 'DELETE'
201→            });
202→
203→            if (!response.ok) {
204→                const errorData = await response.json();
205→                throw new Error(errorData.error || 'Failed to delete release');
206→            }
207→
208→            loadData();
209→        } catch (err) {
210→            setError(err instanceof Error ? err.message : 'Failed to delete release');
211→        }
212→    };
213→
214→    const openEditModal = (release: Release) => {
215→        setSelectedRelease(release);
216→        setFormData({
217→            version: release.version,
218→            name: release.name,
219→            description: release.description || ''
220→        });
221→        setShowEditModal(true);
222→    };
223→
224→    const getStatusBadgeClass = (status: string) => {
225→        switch (status) {
226→            case 'PREPARATION': return 'bg-info text-dark';
227→            case 'ALIGNMENT': return 'bg-warning text-dark';
228→            case 'ACTIVE': return 'bg-success';
229→            case 'ARCHIVED': return 'bg-secondary';
230→            default: return 'bg-light text-dark';
