232→    };
233→
234→    const formatDate = (dateString: string) => {
235→        return new Date(dateString).toLocaleDateString('en-US', {
236→            year: 'numeric',
237→            month: 'short',
238→            day: 'numeric',
239→            hour: '2-digit',
240→            minute: '2-digit'
241→        });
242→    };
243→
244→    if (loading) {
245→        return (
246→            <div className="container-fluid mt-4">
247→                <div className="d-flex justify-content-center">
248→                    <div className="spinner-border" role="status">
249→                        <span className="visually-hidden">Loading...</span>
250→                    </div>
251→                </div>
252→            </div>
253→        );
254→    }
255→
256→    return (
257→        <div className="container-fluid mt-4">
258→            {/* Header Section */}
259→            <div className="row mb-4">
260→                <div className="col-12">
261→                    <div className="d-flex justify-content-between align-items-center">
262→                        <div>
263→                            <h2><i className="bi bi-tags me-2"></i>Release Management</h2>
264→                            <p className="text-muted">Manage system versions and releases</p>
265→                        </div>
266→                        {canCreate && (
