268→                                className="btn btn-primary"
269→                                onClick={() => setShowCreateModal(true)}
270→                            >
271→                                <i className="bi bi-plus-circle me-2"></i>Create New Release
272→                            </button>
273→                        )}
274→                    </div>
275→                </div>
276→            </div>
277→
278→            {/* Error Alert */}
279→            {error && (
