304→                                    <h3>None</h3>
305→                                )}
306→                            </div>
307→                        </div>
308→                    </div>
309→                    <div className="col-md-3">
310→                        <div className="card bg-warning text-dark">
311→                            <div className="card-body">
312→                                <h5 className="card-title">Preparation Releases</h5>
313→                                <h3>{stats.draftCount}</h3>
314→                                <small>In development</small>
315→                            </div>
316→                        </div>
