  1→/**
  2→ * ReleaseList Component
  3→ *
  4→ * Main list view for browsing releases with filtering, search, and pagination
  5→ *
  6→ * Features:
  7→ * - Status filter (ALL, PREPARATION, ALIGNMENT, ACTIVE, ARCHIVED)
  8→ * - Search by version or name
  9→ * - Pagination (20 items per page)
 10→ * - Empty state handling
 11→ * - Click to navigate to detail page
 12→ * - RBAC: Show create button for ADMIN/RELEASE_MANAGER only
 13→ *
 14→ * Related to: Feature 012-build-ui-for, User Story 1 (View and Browse Releases)
 15→ */
 16→
 17→import React, { useState, useEffect } from 'react';
 18→import { releaseService, type Release, type PaginatedResponse } from '../services/releaseService';
 19→import { hasRole, getUser } from '../utils/auth';
 20→import { canDeleteRelease } from '../utils/permissions';
 21→import ReleaseCreateModal from './ReleaseCreateModal';
 22→import ReleaseDeleteConfirm from './ReleaseDeleteConfirm';
 23→import Toast from './Toast';
 24→
 25→interface ReleaseListProps {
 26→    // No props needed - standalone component
 27→}
 28→
 29→const ReleaseList: React.FC<ReleaseListProps> = () => {
 30→    // State
 31→    const [releases, setReleases] = useState<Release[]>([]);
 32→    const [loading, setLoading] = useState(true);
 33→    const [error, setError] = useState<string | null>(null);
 34→    
 35→    // Filters
 36→    const [statusFilter, setStatusFilter] = useState<string>('ALL');
 37→    const [searchQuery, setSearchQuery] = useState('');
 38→    const [debouncedSearch, setDebouncedSearch] = useState('');
 39→    
 40→    // Pagination
 41→    const [currentPage, setCurrentPage] = useState(1);
 42→    const [totalPages, setTotalPages] = useState(1);
 43→    const [totalItems, setTotalItems] = useState(0);
 44→    const pageSize = 20;
 45→
 46→    // Modal state
 47→    const [showCreateModal, setShowCreateModal] = useState(false);
 48→    const [showDeleteModal, setShowDeleteModal] = useState(false);
 49→    const [releaseToDelete, setReleaseToDelete] = useState<Release | null>(null);
 50→    const [isDeleting, setIsDeleting] = useState(false);
 51→
 52→    // Set Active modal state
 53→    const [showActivateModal, setShowActivateModal] = useState(false);
 54→    const [releaseToActivate, setReleaseToActivate] = useState<Release | null>(null);
 55→    const [isActivating, setIsActivating] = useState(false);
 56→
 57→    // Toast state
 58→    const [toast, setToast] = useState<{
 59→        show: boolean;
 60→        message: string;
 61→        type: 'success' | 'error' | 'warning' | 'info';
 62→    }>({
 63→        show: false,
 64→        message: '',
 65→        type: 'success',
 66→    });
 67→
 68→    // User/Role info
 69→    const user = typeof window !== 'undefined' ? getUser() : null;
 70→    const userRoles = user?.roles || [];
 71→    const canCreate = typeof window !== 'undefined' && (hasRole('ADMIN') || hasRole('REQADMIN'));
 72→
 73→    // Debounce search query (300ms)
 74→    useEffect(() => {
 75→        const timer = setTimeout(() => {
 76→            setDebouncedSearch(searchQuery);
 77→            setCurrentPage(1); // Reset to page 1 when search changes
 78→        }, 300);
 79→
 80→        return () => clearTimeout(timer);
 81→    }, [searchQuery]);
 82→
 83→    // Fetch releases
 84→    useEffect(() => {
 85→        if (typeof window !== 'undefined') {
 86→            loadReleases();
 87→        }
 88→    }, [statusFilter, debouncedSearch, currentPage]);
 89→
 90→    async function loadReleases() {
 91→        try {
 92→            setLoading(true);
 93→            setError(null);
 94→
 95→            const result: PaginatedResponse<Release> = await releaseService.list(
 96→                statusFilter,
 97→                currentPage,
 98→                pageSize
 99→            );
100→
101→            setReleases(result.data);
102→            setTotalPages(result.totalPages);
103→            setTotalItems(result.totalItems);
104→            setCurrentPage(result.currentPage);
105→        } catch (err) {
106→            setError(err instanceof Error ? err.message : 'Failed to load releases');
107→            setReleases([]);
108→        } finally {
109→            setLoading(false);
110→        }
111→    }
112→
113→    // Filter releases by search query (client-side if API doesn't support)
114→    const filteredReleases = releases.filter((release) => {
115→        if (!debouncedSearch) return true;
116→        const query = debouncedSearch.toLowerCase();
117→        return (
118→            release.version.toLowerCase().includes(query) ||
119→            release.name.toLowerCase().includes(query)
120→        );
121→    });
122→
123→    // Handle status filter change
124→    function handleStatusChange(e: React.ChangeEvent<HTMLSelectElement>) {
125→        setStatusFilter(e.target.value);
126→        setCurrentPage(1);
127→    }
128→
129→    // Handle search input
130→    function handleSearchChange(e: React.ChangeEvent<HTMLInputElement>) {
131→        setSearchQuery(e.target.value);
132→    }
133→
134→    // Handle page change
135→    function handlePageChange(page: number) {
136→        setCurrentPage(page);
137→        window.scrollTo({ top: 0, behavior: 'smooth' });
138→    }
139→
140→    // Handle create button click
141→    function handleCreateClick() {
142→        setShowCreateModal(true);
143→    }
144→
145→    // Handle create success
146→    function handleCreateSuccess() {
147→        // Show success toast
148→        setToast({
149→            show: true,
150→            message: 'Release created successfully! It has been added to the list with PREPARATION status.',
151→            type: 'success',
152→        });
153→
154→        // Reload releases
155→        loadReleases();
156→    }
157→
158→    // Handle modal close
159→    function handleModalClose() {
160→        setShowCreateModal(false);
161→    }
162→
163→    // Handle toast close
164→    function handleToastClose() {
165→        setToast((prev) => ({ ...prev, show: false }));
166→    }
167→
168→    // Handle delete button click
169→    function handleDeleteClick(release: Release, e: React.MouseEvent) {
170→        e.stopPropagation(); // Prevent row click navigation
171→        setReleaseToDelete(release);
172→        setShowDeleteModal(true);
173→    }
174→
175→    // Handle delete confirmation
176→    async function handleDeleteConfirm() {
177→        if (!releaseToDelete) return;
178→
179→        setIsDeleting(true);
180→        try {
181→            await releaseService.delete(releaseToDelete.id);
182→            
183→            setToast({
184→                show: true,
185→                message: `Release v${releaseToDelete.version} deleted successfully`,
186→                type: 'success',
187→            });
188→
189→            // Close modal
190→            setShowDeleteModal(false);
191→            setReleaseToDelete(null);
192→
193→            // Reload releases
194→            await loadReleases();
195→        } catch (err) {
196→            const errorMessage = err instanceof Error 
197→                ? err.message 
198→                : 'Failed to delete release. Please try again.';
199→            
200→            setToast({
201→                show: true,
202→                message: errorMessage,
203→                type: 'error',
204→            });
205→
206→            // Close modal on error too
207→            setShowDeleteModal(false);
208→            setReleaseToDelete(null);
209→        } finally {
210→            setIsDeleting(false);
211→        }
212→    }
213→
214→    // Handle delete modal close
215→    function handleDeleteModalClose() {
216→        if (!isDeleting) {
217→            setShowDeleteModal(false);
218→            setReleaseToDelete(null);
219→        }
220→    }
221→
222→    // Handle Set Active button click
223→    function handleActivateClick(release: Release, e: React.MouseEvent) {
224→        e.stopPropagation(); // Prevent row click navigation
225→        setReleaseToActivate(release);
226→        setShowActivateModal(true);
227→    }
228→
229→    // Handle Set Active confirmation
230→    async function handleActivateConfirm() {
231→        if (!releaseToActivate) return;
232→
233→        setIsActivating(true);
234→        try {
235→            await releaseService.updateStatus(releaseToActivate.id, 'ACTIVE');
236→
237→            setToast({
238→                show: true,
239→                message: `Release v${releaseToActivate.version} is now active`,
240→                type: 'success',
241→            });
242→
243→            // Close modal
244→            setShowActivateModal(false);
245→            setReleaseToActivate(null);
246→
247→            // Reload releases
248→            await loadReleases();
249→        } catch (err) {
250→            const errorMessage = err instanceof Error
251→                ? err.message
252→                : 'Failed to set release as active. Please try again.';
253→
254→            setToast({
255→                show: true,
256→                message: errorMessage,
257→                type: 'error',
258→            });
259→
260→            // Close modal on error too
261→            setShowActivateModal(false);
262→            setReleaseToActivate(null);
263→        } finally {
264→            setIsActivating(false);
265→        }
266→    }
267→
268→    // Handle Set Active modal close
269→    function handleActivateModalClose() {
270→        if (!isActivating) {
271→            setShowActivateModal(false);
272→            setReleaseToActivate(null);
273→        }
274→    }
275→
276→    // Navigate to detail page
277→    function handleReleaseClick(releaseId: number) {
278→        window.location.href = `/releases/${releaseId}`;
279→    }
280→
281→    // Get status badge class
282→    function getStatusBadgeClass(status: string): string {
283→        switch (status) {
284→            case 'PREPARATION':
285→                return 'bg-info text-dark';
286→            case 'ALIGNMENT':
287→                return 'bg-warning text-dark';
288→            case 'ACTIVE':
289→                return 'bg-success';
290→            case 'ARCHIVED':
291→                return 'bg-secondary';
292→            default:
293→                return 'bg-secondary';
294→        }
295→    }
296→
297→    // Format date
298→    function formatDate(dateString: string | null): string {
299→        if (!dateString) return 'N/A';
300→        const date = new Date(dateString);
301→        return date.toLocaleDateString();
302→    }
303→
304→    // Render loading state
305→    if (loading && releases.length === 0) {
306→        return (
307→            <div className="container mt-4">
308→                <div className="d-flex justify-content-center align-items-center" style={{ minHeight: '400px' }}>
309→                    <div className="spinner-border text-primary" role="status">
310→                        <span className="visually-hidden">Loading...</span>
311→                    </div>
312→                </div>
313→            </div>
314→        );
315→    }
316→
317→    // Render error state
318→    if (error) {
319→        return (
320→            <div className="container mt-4">
321→                <div className="alert alert-danger" role="alert">
322→                    <strong>Error:</strong> {error}
323→                    <button className="btn btn-sm btn-outline-danger ms-3" onClick={loadReleases}>
324→                        Retry
325→                    </button>
326→                </div>
327→            </div>
328→        );
329→    }
330→
331→    // Render empty state
332→    if (!loading && filteredReleases.length === 0 && !debouncedSearch) {
333→        return (
334→            <div className="container mt-4">
335→                <div className="row mb-4">
336→                    <div className="col">
337→                        <h2>Releases</h2>
338→                    </div>
339→                    <div className="col-auto d-flex gap-2">
340→                        <a href="/releases/compare" className="btn btn-outline-primary">
341→                            <i className="bi bi-arrow-left-right me-2"></i>
342→                            Compare Releases
343→                        </a>
344→                        {canCreate && (
345→                            <button className="btn btn-primary" onClick={handleCreateClick}>
346→                                <i className="bi bi-plus-circle me-2"></i>
347→                                Create New Release
348→                            </button>
349→                        )}
350→                    </div>
351→                </div>
352→
353→                <div className="empty-state text-center py-5">
354→                    <i className="bi bi-inbox" style={{ fontSize: '4rem', color: '#6c757d' }}></i>
355→                    <h4 className="mt-3">No releases found</h4>
356→                    <p className="text-muted">
357→                        {canCreate
358→                            ? 'Get started by creating your first release to snapshot requirements.'
359→                            : 'No releases have been created yet. Contact an administrator.'}
360→                    </p>
361→                    {canCreate && (
362→                        <button className="btn btn-primary mt-3" onClick={handleCreateClick}>
363→                            Create First Release
364→                        </button>
365→                    )}
366→                </div>
367→            </div>
368→        );
369→    }
370→
371→    return (
372→        <div className="container mt-4">
373→            {/* Header with Create Button */}
374→            <div className="row mb-4">
375→                <div className="col">
376→                    <h2>Releases</h2>
377→                    <p className="text-muted">
378→                        Manage requirement version snapshots for compliance and audit purposes
379→                    </p>
380→                </div>
381→                <div className="col-auto d-flex gap-2">
382→                    <a href="/releases/compare" className="btn btn-outline-primary">
383→                        <i className="bi bi-arrow-left-right me-2"></i>
384→                        Compare Releases
385→                    </a>
386→                    {canCreate && (
387→                        <button className="btn btn-primary" onClick={handleCreateClick}>
388→                            <i className="bi bi-plus-circle me-2"></i>
389→                            Create New Release
390→                        </button>
391→                    )}
392→                </div>
393→            </div>
394→
395→            {/* Filters and Search */}
396→            <div className="row mb-3">
397→                <div className="col-md-4">
398→                    <label htmlFor="statusFilter" className="form-label">
399→                        Status
400→                    </label>
401→                    <select
402→                        id="statusFilter"
403→                        className="form-select"
404→                        value={statusFilter}
405→                        onChange={handleStatusChange}
406→                        data-testid="status-filter"
407→                    >
408→                        <option value="ALL">All Statuses</option>
409→                        <option value="PREPARATION">Preparation</option>
410→                        <option value="ALIGNMENT">Alignment</option>
411→                        <option value="ACTIVE">Active</option>
412→                        <option value="ARCHIVED">Archived</option>
413→                    </select>
414→                </div>
415→                <div className="col-md-8">
416→                    <label htmlFor="searchBox" className="form-label">
417→                        Search
418→                    </label>
419→                    <input
420→                        id="searchBox"
421→                        type="search"
422→                        className="form-control"
423→                        placeholder="Search by version or name..."
424→                        value={searchQuery}
425→                        onChange={handleSearchChange}
426→                    />
427→                </div>
428→            </div>
429→
430→            {/* Results count */}
431→            {loading && (
432→                <div className="text-center py-3">
433→                    <div className="spinner-border spinner-border-sm text-primary" role="status">
434→                        <span className="visually-hidden">Loading...</span>
435→                    </div>
436→                </div>
437→            )}
438→
439→            {!loading && (
440→                <p className="text-muted mb-3">
441→                    Showing {filteredReleases.length} of {totalItems} releases
442→                </p>
443→            )}
444→
445→            {/* Releases Table */}
446→            <div className="table-responsive">
447→                <table className="table table-hover">
448→                    <thead>
449→                        <tr>
450→                            <th>Version</th>
451→                            <th>Name</th>
452→                            <th>Status</th>
453→                            <th>Created By</th>
454→                            <th>Created Date</th>
455→                            <th>Requirements</th>
456→                            <th>Actions</th>
457→                        </tr>
458→                    </thead>
459→                    <tbody>
460→                        {filteredReleases.map((release) => (
461→                            <tr
462→                                key={release.id}
463→                                onClick={() => handleReleaseClick(release.id)}
464→                                style={{ cursor: 'pointer' }}
465→                                data-testid={`release-card-${release.id}`}
466→                            >
467→                                <td>
468→                                    <span data-testid="release-version">
469→                                        {release.version}
470→                                    </span>
471→                                </td>
472→                                <td>
473→                                    <a href={`/releases/${release.id}`} onClick={(e) => e.preventDefault()}>
474→                                        {release.name}
475→                                    </a>
476→                                </td>
477→                                <td>
478→                                    <span 
479→                                        className={`badge ${getStatusBadgeClass(release.status)}`}
480→                                        aria-label={`Release status: ${release.status}`}
481→                                    >
482→                                        {release.status}
483→                                    </span>
484→                                </td>
485→                                <td>{release.createdBy}</td>
486→                                <td>{formatDate(release.createdAt)}</td>
487→                                <td>
488→                                    <span className="badge bg-info">{release.requirementCount}</span>
489→                                </td>
490→                                <td onClick={(e) => e.stopPropagation()}>
491→                                    <div className="d-flex gap-1">
492→                                        {(release.status === 'PREPARATION' || release.status === 'ALIGNMENT') && canCreate && (
493→                                            <button
494→                                                className="btn btn-sm btn-outline-info"
495→                                                onClick={(e) => handleActivateClick(release, e)}
496→                                                title="Set this release as active"
497→                                                data-testid={`activate-release-${release.id}`}
498→                                            >
499→                                                <i className="bi bi-check-circle"></i>
500→                                            </button>
501→                                        )}
502→                                        {canDeleteRelease(release, user, userRoles) && (
503→                                            <button
504→                                                className="btn btn-sm btn-outline-danger"
505→                                                onClick={(e) => handleDeleteClick(release, e)}
506→                                                title="Delete release"
507→                                                data-testid={`delete-release-${release.id}`}
508→                                            >
509→                                                <i className="bi bi-trash"></i>
510→                                            </button>
511→                                        )}
512→                                    </div>
513→                                </td>
514→                            </tr>
515→                        ))}
516→                    </tbody>
517→                </table>
518→            </div>
519→
520→            {/* No results message (after search) */}
521→            {!loading && filteredReleases.length === 0 && debouncedSearch && (
522→                <div className="text-center py-4">
523→                    <p className="text-muted">No releases match your search criteria.</p>
524→                </div>
525→            )}
526→
527→            {/* Pagination */}
528→            {totalPages > 1 && (
529→                <nav aria-label="Release pagination" className="mt-4">
530→                    <ul className="pagination justify-content-center" data-testid="pagination">
531→                        <li className={`page-item ${currentPage === 1 ? 'disabled' : ''}`}>
532→                            <button
533→                                className="page-link"
534→                                onClick={() => handlePageChange(currentPage - 1)}
535→                                disabled={currentPage === 1}
536→                                data-testid="prev-page"
537→                            >
538→                                Previous
539→                            </button>
540→                        </li>
541→
542→                        {[...Array(totalPages)].map((_, index) => {
543→                            const page = index + 1;
544→                            // Show first page, last page, current page, and pages around current
545→                            if (
546→                                page === 1 ||
547→                                page === totalPages ||
548→                                (page >= currentPage - 2 && page <= currentPage + 2)
549→                            ) {
550→                                return (
551→                                    <li
552→                                        key={page}
553→                                        className={`page-item ${currentPage === page ? 'active' : ''}`}
554→                                    >
555→                                        <button
556→                                            className="page-link"
557→                                            onClick={() => handlePageChange(page)}
558→                                            data-testid={`page-${page}`}
559→                                        >
560→                                            {page}
561→                                        </button>
562→                                    </li>
563→                                );
564→                            } else if (page === currentPage - 3 || page === currentPage + 3) {
565→                                return (
566→                                    <li key={page} className="page-item disabled">
567→                                        <span className="page-link">...</span>
568→                                    </li>
569→                                );
570→                            }
571→                            return null;
572→                        })}
573→
574→                        <li className={`page-item ${currentPage === totalPages ? 'disabled' : ''}`}>
575→                            <button
576→                                className="page-link"
577→                                onClick={() => handlePageChange(currentPage + 1)}
578→                                disabled={currentPage === totalPages}
579→                                data-testid="next-page"
580→                            >
581→                                Next
582→                            </button>
583→                        </li>
584→                    </ul>
585→                </nav>
586→            )}
587→
588→            {/* Create Release Modal */}
589→            <ReleaseCreateModal
590→                isOpen={showCreateModal}
591→                onClose={handleModalClose}
592→                onSuccess={handleCreateSuccess}
593→            />
594→
595→            {/* Delete Release Modal */}
596→            <ReleaseDeleteConfirm
597→                release={releaseToDelete}
598→                isOpen={showDeleteModal}
599→                isDeleting={isDeleting}
600→                onClose={handleDeleteModalClose}
601→                onConfirm={handleDeleteConfirm}
602→            />
603→
604→            {/* Set Active Release Modal */}
605→            {showActivateModal && releaseToActivate && (
606→                <>
607→                    <div
608→                        className="modal-backdrop fade show"
609→                        onClick={isActivating ? undefined : handleActivateModalClose}
610→                        style={{ zIndex: 1040 }}
611→                    ></div>
612→                    <div
613→                        className="modal fade show d-block"
614→                        tabIndex={-1}
615→                        role="dialog"
616→                        style={{ zIndex: 1050 }}
617→                        aria-labelledby="activateModalLabel"
618→                        aria-modal="true"
619→                    >
620→                        <div className="modal-dialog">
621→                            <div className="modal-content">
622→                                <div className="modal-header">
623→                                    <h5 className="modal-title" id="activateModalLabel">
624→                                        Set Release as Active
625→                                    </h5>
626→                                    <button
627→                                        type="button"
628→                                        className="btn-close"
629→                                        aria-label="Close"
630→                                        onClick={handleActivateModalClose}
631→                                        disabled={isActivating}
632→                                    ></button>
633→                                </div>
634→                                <div className="modal-body">
635→                                    <p>
636→                                        Are you sure you want to set{' '}
637→                                        <strong>{releaseToActivate.version} - {releaseToActivate.name}</strong>{' '}
638→                                        as the active release?
639→                                    </p>
640→                                    <p className="text-muted mb-0">
641→                                        This will mark this release as the currently active version.
642→                                    </p>
643→                                </div>
644→                                <div className="modal-footer">
645→                                    <button
646→                                        type="button"
647→                                        className="btn btn-secondary"
648→                                        onClick={handleActivateModalClose}
649→                                        disabled={isActivating}
650→                                    >
651→                                        Cancel
652→                                    </button>
653→                                    <button
654→                                        type="button"
655→                                        className="btn btn-info"
656→                                        onClick={handleActivateConfirm}
657→                                        disabled={isActivating}
658→                                    >
659→                                        {isActivating ? (
660→                                            <>
661→                                                <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
662→                                                Setting Active...
663→                                            </>
664→                                        ) : (
665→                                            'Confirm Set Active'
666→                                        )}
667→                                    </button>
668→                                </div>
669→                            </div>
670→                        </div>
671→                    </div>
672→                </>
673→            )}
674→
675→            {/* Toast Notifications */}
676→            <Toast
677→                message={toast.message}
678→                type={toast.type}
679→                show={toast.show}
680→                onClose={handleToastClose}
681→            />
682→        </div>
683→    );
684→};
