  1→/**
  2→ * Alignment Review Service
  3→ *
  4→ * Handles public API calls for reviewers accessing via token link.
  5→ * These endpoints don't require authentication - the token serves as auth.
  6→ *
  7→ * Feature: 068-requirements-alignment-process
  8→ */
  9→
 10→import type { ReviewPageData, AlignmentSnapshot } from './releaseService';
 11→
 12→const API_BASE = import.meta.env.PUBLIC_API_URL || '';
 13→
 14→export type ReviewAssessment = 'OK' | 'CHANGE' | 'NOGO';
 15→
 16→export interface SubmitReviewRequest {
 17→    snapshotId: number;
 18→    assessment: ReviewAssessment;
 19→    comment?: string;
 20→}
 21→
 22→export interface SubmitReviewResult {
 23→    success: boolean;
 24→    reviewId: number;
 25→    assessment: string;
 26→    message: string;
 27→}
 28→
 29→/**
 30→ * Alignment Review Service for token-based reviewer access
 31→ */
 32→export interface ImportReviewResult {
 33→    success: boolean;
 34→    imported: number;
 35→    skipped: number;
 36→    errors: string[];
 37→    message: string;
 38→}
 39→
 40→export const alignmentReviewService = {
 41→    /**
 42→     * Get review page data using token
 43→     *
 44→     * @param token Review token from email link
 45→     * @returns Review page data including snapshots and existing reviews
 46→     */
 47→    async getReviewPageData(token: string): Promise<ReviewPageData> {
 48→        const response = await fetch(`${API_BASE}/api/alignment/review/${token}`);
 49→
 50→        if (!response.ok) {
 51→            if (response.status === 404) {
 52→                throw new Error('Invalid or expired review link');
 53→            }
 54→            throw new Error(`Failed to load review page: ${response.statusText}`);
 55→        }
 56→
 57→        return response.json();
 58→    },
 59→
 60→    /**
 61→     * Submit a review for a requirement
 62→     *
 63→     * @param token Review token
 64→     * @param snapshotId ID of the requirement snapshot
 65→     * @param assessment Assessment (OK, CHANGE, NOGO)
 66→     * @param comment Optional comment
 67→     * @returns Submit result
 68→     */
 69→    async submitReview(
 70→        token: string,
 71→        snapshotId: number,
 72→        assessment: ReviewAssessment,
 73→        comment?: string
 74→    ): Promise<SubmitReviewResult> {
 75→        const response = await fetch(`${API_BASE}/api/alignment/review/${token}`, {
 76→            method: 'POST',
 77→            headers: {
 78→                'Content-Type': 'application/json',
 79→            },
 80→            body: JSON.stringify({
 81→                snapshotId,
 82→                assessment,
 83→                comment,
 84→            }),
 85→        });
 86→
 87→        if (!response.ok) {
 88→            const errorData = await response.json().catch(() => ({}));
 89→            throw new Error(errorData.message || `Failed to submit review: ${response.statusText}`);
 90→        }
 91→
 92→        return response.json();
 93→    },
 94→
 95→    /**
 96→     * Mark review as complete
 97→     *
 98→     * @param token Review token
 99→     * @returns Completion result
100→     */
101→    async completeReview(token: string): Promise<{ success: boolean; message: string }> {
102→        const response = await fetch(`${API_BASE}/api/alignment/review/${token}/complete`, {
103→            method: 'POST',
104→        });
105→
106→        if (!response.ok) {
107→            const errorData = await response.json().catch(() => ({}));
108→            throw new Error(errorData.message || `Failed to complete review: ${response.statusText}`);
109→        }
110→
111→        return response.json();
112→    },
113→
114→    /**
115→     * Get the URL for downloading the review export Excel file
116→     */
117→    getExportUrl(token: string): string {
118→        return `${API_BASE}/api/alignment/review/${token}/export`;
119→    },
120→
121→    /**
122→     * Import reviews from an Excel file
123→     */
124→    async importReviews(token: string, file: File): Promise<ImportReviewResult> {
125→        const formData = new FormData();
126→        formData.append('file', file);
127→
128→        const response = await fetch(`${API_BASE}/api/alignment/review/${token}/import`, {
129→            method: 'POST',
130→            body: formData,
131→        });
132→
133→        if (!response.ok) {
134→            const errorData = await response.json().catch(() => ({}));
135→            throw new Error(errorData.message || `Failed to import reviews: ${response.statusText}`);
136→        }
137→
138→        return response.json();
139→    },
140→};
