  1→/**
  2→ * AlignmentResultsPage Component
  3→ *
  4→ * Public read-only page for viewing alignment results after finalization.
  5→ * Accessed via token link from finalization notification email.
  6→ * Shows accepted/rejected decisions for each requirement change.
  7→ */
  8→
  9→import React, { useState, useEffect } from 'react';
 10→
 11→const API_BASE = import.meta.env.PUBLIC_API_URL || '';
 12→
 13→type FilterType = 'all' | 'accepted' | 'rejected' | 'noDecision';
 14→
 15→interface AlignmentResultsPageProps {
 16→    token: string;
 17→}
 18→
 19→interface ResultsData {
 20→    session: {
 21→        id: number;
 22→        releaseName: string;
 23→        releaseVersion: string;
 24→        status: string;
 25→        changedRequirementsCount: number;
 26→        startedAt: string | null;
 27→        completedAt: string | null;
 28→        completionNotes: string | null;
 29→    };
 30→    summary: {
 31→        total: number;
 32→        accepted: number;
 33→        rejected: number;
 34→        noDecision: number;
 35→    };
 36→    requirements: RequirementResult[];
 37→}
 38→
 39→interface RequirementResult {
 40→    snapshotId: number;
 41→    requirementId: string;
 42→    shortreq: string;
 43→    details: string | null;
 44→    changeType: string;
 45→    chapter: string | null;
 46→    assessments: {
 47→        ok: number;
 48→        change: number;
 49→        nogo: number;
 50→    };
 51→    reviews: {
 52→        reviewerName: string;
 53→        assessment: string;
 54→        comment: string | null;
 55→    }[];
 56→    adminDecision: {
 57→        decision: string;
 58→        comment: string | null;
 59→        decidedBy: string;
 60→    } | null;
 61→}
 62→
 63→export const AlignmentResultsPage: React.FC<AlignmentResultsPageProps> = ({ token }) => {
 64→    const [data, setData] = useState<ResultsData | null>(null);
 65→    const [isLoading, setIsLoading] = useState(true);
 66→    const [error, setError] = useState<string | null>(null);
 67→    const [filter, setFilter] = useState<FilterType>('all');
 68→    const [expandedSnapshot, setExpandedSnapshot] = useState<number | null>(null);
 69→
 70→    useEffect(() => {
 71→        loadData();
 72→    }, [token]);
 73→
 74→    const loadData = async () => {
 75→        setIsLoading(true);
 76→        setError(null);
 77→
 78→        try {
 79→            const response = await fetch(`${API_BASE}/api/alignment/results/${token}`);
 80→            if (!response.ok) {
 81→                if (response.status === 404) {
 82→                    throw new Error('Invalid or expired results link');
 83→                }
 84→                throw new Error(`Failed to load results: ${response.statusText}`);
 85→            }
 86→            const resultsData = await response.json();
 87→            setData(resultsData);
 88→        } catch (err) {
 89→            setError(err instanceof Error ? err.message : 'Failed to load alignment results');
 90→        } finally {
 91→            setIsLoading(false);
 92→        }
 93→    };
 94→
 95→    const getFilteredRequirements = (): RequirementResult[] => {
 96→        if (!data) return [];
 97→        switch (filter) {
 98→            case 'accepted':
 99→                return data.requirements.filter(r => r.adminDecision?.decision === 'ACCEPTED');
100→            case 'rejected':
101→                return data.requirements.filter(r => r.adminDecision?.decision === 'REJECTED');
102→            case 'noDecision':
103→                return data.requirements.filter(r => !r.adminDecision);
104→            default:
105→                return data.requirements;
106→        }
107→    };
108→
109→    const formatDate = (dateStr: string | null): string => {
110→        if (!dateStr) return '—';
111→        try {
112→            return new Date(dateStr).toLocaleDateString('en-US', {
113→                year: 'numeric',
114→                month: 'short',
115→                day: 'numeric',
116→                hour: '2-digit',
117→                minute: '2-digit',
118→            });
119→        } catch {
120→            return dateStr;
121→        }
122→    };
123→
124→    const getChangeTypeBadge = (changeType: string) => {
125→        const colors: Record<string, string> = {
126→            ADDED: 'bg-success',
127→            MODIFIED: 'bg-warning text-dark',
128→            DELETED: 'bg-danger',
129→        };
130→        return (
131→            <span className={`badge ${colors[changeType] || 'bg-secondary'}`}>
132→                {changeType}
133→            </span>
134→        );
135→    };
136→
137→    const getDecisionBadge = (decision: string | null | undefined) => {
138→        if (!decision) {
139→            return <span className="badge bg-secondary">No Decision</span>;
140→        }
141→        if (decision === 'ACCEPTED') {
142→            return <span className="badge bg-success">Accepted</span>;
143→        }
144→        return <span className="badge bg-danger">Rejected</span>;
145→    };
146→
147→    const getAssessmentBadge = (assessment: string) => {
148→        const colors: Record<string, string> = {
149→            OK: 'bg-success',
150→            CHANGE: 'bg-warning text-dark',
151→            NOGO: 'bg-danger',
152→        };
153→        return (
154→            <span className={`badge ${colors[assessment] || 'bg-secondary'} me-1`}>
155→                {assessment}
156→            </span>
157→        );
158→    };
159→
160→    // Loading state
161→    if (isLoading) {
162→        return (
163→            <div className="container py-5">
164→                <div className="text-center">
165→                    <div className="spinner-border text-primary" role="status">
166→                        <span className="visually-hidden">Loading...</span>
167→                    </div>
168→                    <p className="mt-3 text-muted">Loading alignment results...</p>
169→                </div>
170→            </div>
171→        );
172→    }
173→
174→    // Error state
175→    if (error) {
176→        return (
177→            <div className="container py-5">
178→                <div className="row justify-content-center">
179→                    <div className="col-md-6">
180→                        <div className="card border-danger">
181→                            <div className="card-body text-center">
182→                                <i className="bi bi-exclamation-triangle text-danger" style={{ fontSize: '3rem' }}></i>
183→                                <h4 className="mt-3">Unable to Load Results</h4>
184→                                <p className="text-muted">{error}</p>
185→                                <button className="btn btn-primary" onClick={loadData}>
186→                                    <i className="bi bi-arrow-clockwise me-2"></i>Try Again
187→                                </button>
188→                            </div>
189→                        </div>
190→                    </div>
191→                </div>
192→            </div>
193→        );
194→    }
195→
196→    if (!data) return null;
197→
198→    const filtered = getFilteredRequirements();
199→
200→    return (
201→        <div className="container py-4" style={{ maxWidth: '960px' }}>
202→            {/* Header */}
203→            <div className="text-center mb-4">
204→                <div
205→                    className="p-4 rounded-top"
206→                    style={{
207→                        background: 'linear-gradient(135deg, #28a745 0%, #20c997 100%)',
208→                    }}
209→                >
210→                    <h1 className="text-white mb-1" style={{ fontSize: '1.75rem' }}>
211→                        <i className="bi bi-check-circle me-2"></i>
212→                        Alignment Results
213→                    </h1>
214→                    <p className="text-white-50 mb-0">
215→                        {data.session.releaseName} v{data.session.releaseVersion}
216→                    </p>
217→                </div>
218→                <div className="bg-white p-3 rounded-bottom shadow-sm border border-top-0">
219→                    <div className="row text-muted small">
220→                        <div className="col-sm-6">
221→                            <i className="bi bi-calendar-event me-1"></i>
222→                            Started: {formatDate(data.session.startedAt)}
223→                        </div>
224→                        <div className="col-sm-6">
225→                            <i className="bi bi-calendar-check me-1"></i>
226→                            Completed: {formatDate(data.session.completedAt)}
227→                        </div>
228→                    </div>
229→                    {data.session.completionNotes && (
230→                        <p className="text-muted small mt-2 mb-0">
231→                            <i className="bi bi-chat-left-text me-1"></i>
232→                            {data.session.completionNotes}
233→                        </p>
234→                    )}
235→                </div>
236→            </div>
237→
238→            {/* Summary Stats */}
239→            <div className="row g-3 mb-4">
240→                <div className="col-6 col-md-3">
241→                    <div className="card text-center h-100">
242→                        <div className="card-body py-3">
243→                            <div className="fs-3 fw-bold text-primary">{data.summary.total}</div>
244→                            <div className="text-muted small">Total Changes</div>
245→                        </div>
246→                    </div>
247→                </div>
248→                <div className="col-6 col-md-3">
249→                    <div className="card text-center h-100">
250→                        <div className="card-body py-3">
251→                            <div className="fs-3 fw-bold text-success">{data.summary.accepted}</div>
252→                            <div className="text-muted small">Accepted</div>
253→                        </div>
254→                    </div>
255→                </div>
256→                <div className="col-6 col-md-3">
257→                    <div className="card text-center h-100">
258→                        <div className="card-body py-3">
259→                            <div className="fs-3 fw-bold text-danger">{data.summary.rejected}</div>
260→                            <div className="text-muted small">Rejected</div>
261→                        </div>
262→                    </div>
263→                </div>
264→                <div className="col-6 col-md-3">
265→                    <div className="card text-center h-100">
266→                        <div className="card-body py-3">
267→                            <div className="fs-3 fw-bold text-secondary">{data.summary.noDecision}</div>
268→                            <div className="text-muted small">No Decision</div>
269→                        </div>
270→                    </div>
271→                </div>
272→            </div>
273→
274→            {/* Filter Tabs */}
275→            <ul className="nav nav-pills mb-3">
276→                <li className="nav-item">
277→                    <button
278→                        className={`nav-link ${filter === 'all' ? 'active' : ''}`}
279→                        onClick={() => setFilter('all')}
280→                    >
281→                        All <span className="badge bg-light text-dark ms-1">{data.summary.total}</span>
282→                    </button>
283→                </li>
284→                <li className="nav-item">
285→                    <button
286→                        className={`nav-link ${filter === 'accepted' ? 'active' : ''}`}
287→                        onClick={() => setFilter('accepted')}
288→                    >
289→                        <i className="bi bi-check-circle me-1"></i>Accepted{' '}
290→                        <span className="badge bg-light text-dark ms-1">{data.summary.accepted}</span>
291→                    </button>
292→                </li>
293→                <li className="nav-item">
294→                    <button
295→                        className={`nav-link ${filter === 'rejected' ? 'active' : ''}`}
296→                        onClick={() => setFilter('rejected')}
297→                    >
298→                        <i className="bi bi-x-circle me-1"></i>Rejected{' '}
299→                        <span className="badge bg-light text-dark ms-1">{data.summary.rejected}</span>
300→                    </button>
301→                </li>
302→                <li className="nav-item">
303→                    <button
304→                        className={`nav-link ${filter === 'noDecision' ? 'active' : ''}`}
305→                        onClick={() => setFilter('noDecision')}
306→                    >
