336→                                                {getChangeTypeBadge(req.changeType)}
337→                                                {getDecisionBadge(req.adminDecision?.decision)}
338→                                            </div>
339→                                            <p className="mb-0 text-truncate" style={{ maxWidth: '700px' }}>
340→                                                {req.shortreq}
341→                                            </p>
342→                                        </div>
343→                                        <div className="ms-3 text-muted">
