345→                                                className={`bi bi-chevron-${isExpanded ? 'up' : 'down'}`}
346→                                            ></i>
347→                                        </div>
348→                                    </div>
349→
350→                                    {/* Assessment summary (always visible) */}
351→                                    <div className="mt-2">
352→                                        {req.assessments.ok > 0 && (
