406→                                                    <p className="mb-0 mt-1 small">
407→                                                        {req.adminDecision.comment}
408→                                                    </p>
409→                                                )}
410→                                            </div>
411→                                        )}
412→
413→                                        {/* Reviewer assessments */}
414→                                        {req.reviews.length > 0 && (
415→                                            <>
416→                                                <h6 className="text-muted small text-uppercase mb-2">
