434→                                                                    {review.comment}
435→                                                                </p>
436→                                                            )}
437→                                                        </div>
438→                                                    ))}
439→                                                </div>
440→                                            </>
441→                                        )}
442→
443→                                        {req.reviews.length === 0 && (
444→                                            <p className="text-muted small mb-0">
445→                                                No reviewer assessments submitted.
446→                                            </p>
447→                                        )}
448→                                    </div>
449→                                )}
450→                            </div>
451→                        );
452→                    })}
453→                </div>
454→            )}
455→
456→            {/* Footer */}
