 31→    const [isImporting, setIsImporting] = useState(false);
 32→    const fileInputRef = useRef<HTMLInputElement>(null);
 33→
 34→    // Track local reviews for optimistic updates
 35→    const [localReviews, setLocalReviews] = useState<Map<number, { assessment: ReviewAssessment; comment: string | null }>>(new Map());
 36→
 37→    useEffect(() => {
 38→        loadData();
 39→    }, [token]);
 40→
 41→    const loadData = async () => {
 42→        setIsLoading(true);
 43→        setError(null);
 44→
 45→        try {
 46→            const data = await alignmentReviewService.getReviewPageData(token);
 47→            setPageData(data);
 48→
 49→            // Initialize local reviews from existing data
 50→            const reviews = new Map<number, { assessment: ReviewAssessment; comment: string | null }>();
 51→            data.snapshots.forEach((snapshot) => {
 52→                if (snapshot.existingReview) {
 53→                    reviews.set(snapshot.id, {
 54→                        assessment: snapshot.existingReview.assessment,
 55→                        comment: snapshot.existingReview.comment,
 56→                    });
 57→                }
 58→            });
 59→            setLocalReviews(reviews);
 60→        } catch (err) {
 61→            setError(err instanceof Error ? err.message : 'Failed to load review page');
 62→        } finally {
 63→            setIsLoading(false);
 64→        }
 65→    };
 66→
 67→    const handleSubmitReview = async (
 68→        snapshotId: number,
 69→        assessment: ReviewAssessment,
 70→        comment?: string
 71→    ) => {
 72→        setSavingSnapshot(snapshotId);
 73→
 74→        try {
 75→            await alignmentReviewService.submitReview(token, snapshotId, assessment, comment);
 76→
 77→            // Update local state
 78→            setLocalReviews((prev) => {
 79→                const next = new Map(prev);
 80→                next.set(snapshotId, { assessment, comment: comment || null });
 81→                return next;
 82→            });
 83→        } catch (err) {
 84→            alert(err instanceof Error ? err.message : 'Failed to submit review');
 85→        } finally {
 86→            setSavingSnapshot(null);
 87→        }
 88→    };
 89→
 90→    const handleCompleteReview = async () => {
 91→        if (!confirm('Are you sure you want to mark your review as complete? You can still update individual assessments later.')) {
 92→            return;
 93→        }
 94→
 95→        try {
 96→            await alignmentReviewService.completeReview(token);
