391→// Requirement Card Sub-component
392→interface RequirementCardProps {
393→    snapshot: AlignmentSnapshot;
394→    review?: { assessment: ReviewAssessment; comment: string | null };
395→    isExpanded: boolean;
396→    isSaving: boolean;
397→    isOpen: boolean;
398→    onToggleExpand: () => void;
399→    onSubmitReview: (assessment: ReviewAssessment, comment?: string) => void;
400→}
401→
402→const RequirementCard: React.FC<RequirementCardProps> = ({
403→    snapshot,
404→    review,
405→    isExpanded,
406→    isSaving,
407→    isOpen,
408→    onToggleExpand,
409→    onSubmitReview,
410→}) => {
411→    const [comment, setComment] = useState(review?.comment || '');
412→    const [selectedAssessment, setSelectedAssessment] = useState<ReviewAssessment | null>(
413→        review?.assessment || null
414→    );
415→
416→    const handleSave = () => {
417→        if (!selectedAssessment) return;
418→        onSubmitReview(selectedAssessment, comment || undefined);
419→    };
420→
421→    const getChangeTypeBadge = () => {
422→        switch (snapshot.changeType) {
423→            case 'ADDED':
424→                return <span className="badge bg-success">Added</span>;
425→            case 'DELETED':
426→                return <span className="badge bg-danger">Deleted</span>;
427→            case 'MODIFIED':
428→                return <span className="badge bg-warning text-dark">Modified</span>;
429→        }
430→    };
431→
432→    const getAssessmentBadge = () => {
433→        if (!review) return null;
434→        switch (review.assessment) {
435→            case 'OK':
436→                return <span className="badge bg-success">OK</span>;
437→            case 'CHANGE':
438→                return <span className="badge bg-warning text-dark">Change</span>;
439→            case 'NOGO':
440→                return <span className="badge bg-danger">NOGO</span>;
441→        }
442→    };
443→
444→    return (
445→        <div className={`card mb-3 shadow-sm ${review ? 'border-start border-4 border-success' : ''}`}>
446→            <div
447→                className="card-header bg-white d-flex justify-content-between align-items-center"
448→                style={{ cursor: 'pointer' }}
449→                onClick={onToggleExpand}
450→            >
451→                <div className="d-flex align-items-center gap-2">
452→                    {getChangeTypeBadge()}
453→                    <strong>{snapshot.requirementId}</strong>
454→                    {getAssessmentBadge()}
455→                </div>
456→                <i className={`bi bi-chevron-${isExpanded ? 'up' : 'down'}`}></i>
457→            </div>
458→
459→            <div className="card-body">
460→                <p className="mb-2">{snapshot.shortreq}</p>
461→
462→                {isExpanded && (
463→                    <div className="mt-3">
464→                        {/* Diff View for Modified */}
465→                        {snapshot.changeType === 'MODIFIED' && snapshot.previousShortreq && (
466→                            <div className="mb-3">
467→                                <h6 className="text-muted small">Changes:</h6>
468→                                <div className="bg-danger bg-opacity-10 p-2 rounded mb-2">
469→                                    <small className="text-danger">
470→                                        <i className="bi bi-dash-circle me-1"></i>
471→                                        {snapshot.previousShortreq}
472→                                    </small>
473→                                </div>
474→                                <div className="bg-success bg-opacity-10 p-2 rounded">
475→                                    <small className="text-success">
476→                                        <i className="bi bi-plus-circle me-1"></i>
477→                                        {snapshot.shortreq}
478→                                    </small>
479→                                </div>
480→                            </div>
481→                        )}
482→
483→                        {/* Details if available */}
484→                        {snapshot.details && (
485→                            <div className="mb-3">
486→                                <h6 className="text-muted small">Details:</h6>
487→                                <p className="small mb-0 bg-light p-2 rounded">{snapshot.details}</p>
488→                            </div>
489→                        )}
490→
491→                        {/* Assessment Buttons */}
492→                        {isOpen && (
493→                            <div className="mt-3 pt-3 border-top">
494→                                <h6 className="mb-2">Your Assessment</h6>
495→                                <div className="d-flex gap-2 mb-3">
496→                                    <button
497→                                        className={`btn ${selectedAssessment === 'OK' ? 'btn-success' : 'btn-outline-success'}`}
498→                                        onClick={() => setSelectedAssessment('OK')}
499→                                        disabled={isSaving}
500→                                    >
501→                                        <i className="bi bi-check me-1"></i>
502→                                        OK
503→                                    </button>
504→                                    <button
505→                                        className={`btn ${selectedAssessment === 'CHANGE' ? 'btn-warning' : 'btn-outline-warning'}`}
506→                                        onClick={() => setSelectedAssessment('CHANGE')}
507→                                        disabled={isSaving}
508→                                    >
509→                                        <i className="bi bi-exclamation-triangle me-1"></i>
510→                                        Change
511→                                    </button>
512→                                    <button
513→                                        className={`btn ${selectedAssessment === 'NOGO' ? 'btn-danger' : 'btn-outline-danger'}`}
514→                                        onClick={() => setSelectedAssessment('NOGO')}
515→                                        disabled={isSaving}
516→                                    >
517→                                        <i className="bi bi-x-circle me-1"></i>
518→                                        NOGO
519→                                    </button>
520→                                </div>
521→
522→                                <div className="mb-3">
523→                                    <textarea
524→                                        className="form-control"
525→                                        rows={2}
526→                                        placeholder="Optional comment..."
527→                                        value={comment}
528→                                        onChange={(e) => setComment(e.target.value)}
529→                                        disabled={isSaving}
530→                                    />
531→                                </div>
532→
533→                                <button
534→                                    className="btn btn-primary"
535→                                    onClick={handleSave}
536→                                    disabled={!selectedAssessment || isSaving}
537→                                >
538→                                    {isSaving ? (
539→                                        <>
540→                                            <span className="spinner-border spinner-border-sm me-2"></span>
541→                                            Saving...
542→                                        </>
543→                                    ) : (
544→                                        <>
545→                                            <i className="bi bi-save me-2"></i>
546→                                            Save Assessment
547→                                        </>
548→                                    )}
549→                                </button>
550→                            </div>
551→                        )}
552→                    </div>
553→                )}
554→            </div>
555→        </div>
556→    );
557→};
