  2→ * ReleaseStatusActions Component
  3→ *
  4→ * Provides status transition buttons for releases
  5→ * Enforces workflow: PREPARATION → ALIGNMENT → ACTIVE, ACTIVE → ARCHIVED (automatic)
  6→ *
  7→ * Features:
  8→ * - Shows "Start Alignment" button for PREPARATION releases (ADMIN/RELEASE_MANAGER only)
  9→ * - Shows alignment dashboard link for ALIGNMENT releases
 10→ * - Shows "Set Active" button for ALIGNMENT releases after alignment
 11→ * - When a release is set to ACTIVE, the previously ACTIVE release becomes ARCHIVED
 12→ * - Confirmation modal before transitions
 13→ * - Loading state during API calls
 14→ * - Error handling with user feedback
 15→ *
 16→ * Related to: Feature 012-build-ui-for, User Story 5 (Status Lifecycle)
 17→ * Updated for: Feature 068-requirements-alignment-process
 18→ */
 19→
 20→import React, { useState, useEffect } from 'react';
 21→import { releaseService, type Release, type AlignmentStatus } from '../services/releaseService';
 22→import { hasRole } from '../utils/auth';
 23→
 24→interface ReleaseStatusActionsProps {
 25→    release: Release;
 26→    onStatusChange: (updatedRelease: Release) => void;
 27→    onAlignmentStart?: () => void;
 28→}
 29→
 30→/**
 31→ * Status transition confirmation modal
 32→ */
 33→interface StatusTransitionModalProps {
 34→    release: Release;
 35→    isOpen: boolean;
 36→    isLoading: boolean;
 37→    onClose: () => void;
 38→    onConfirm: () => void;
 39→}
 40→
 41→const StatusTransitionModal: React.FC<StatusTransitionModalProps> = ({
 42→    release,
 43→    isOpen,
 44→    isLoading,
 45→    onClose,
 46→    onConfirm
 47→}) => {
 48→    // Handle keyboard navigation (Escape to close)
 49→    React.useEffect(() => {
 50→        if (!isOpen) return;
 51→
 52→        function handleKeyDown(e: KeyboardEvent) {
 53→            if (e.key === 'Escape' && !isLoading) {
 54→                onClose();
 55→            }
 56→        }
 57→
 58→        document.addEventListener('keydown', handleKeyDown);
 59→        return () => document.removeEventListener('keydown', handleKeyDown);
 60→    }, [isOpen, isLoading, onClose]);
 61→
 62→    if (!isOpen) {
 63→        return null;
 64→    }
 65→
 66→    return (
 67→        <>
